"""Production-grade token budget management for an agent system.

Demonstrates how to stay within context limits when building
multi-turn agent prompts.
"""
import tiktoken
from dataclasses import dataclass
from typing import Literal


@dataclass
class TokenBudget:
    model: str = "gpt-4"
    max_context: int = 128_000
    reserved_for_reply: int = 4_096

    def __post_init__(self) -> None:
        self._enc = tiktoken.encoding_for_model(self.model)
        self._messages: list = []
        self._token_counts: list = []

    @property
    def used_tokens(self) -> int:
        # 3 tokens overhead per message + 3 for reply priming
        return sum(self._token_counts) + 3 * len(self._messages) + 3

    @property
    def remaining_for_reply(self) -> int:
        return self.max_context - self.used_tokens

    def can_add(self, role: str, content: str) -> bool:
        msg_tokens = 3 + len(self._enc.encode(role)) + len(self._enc.encode(content))
        return self.used_tokens + msg_tokens + self.reserved_for_reply <= self.max_context

    def add_message(self, role: str, content: str) -> bool:
        if not self.can_add(role, content):
            return False
        msg_tokens = len(self._enc.encode(role)) + len(self._enc.encode(content))
        self._messages.append({"role": role, "content": content})
        self._token_counts.append(msg_tokens)
        return True

    def prune_oldest_user_messages(self, n: int = 1) -> None:
        """Drop the oldest non-system messages to reclaim context budget."""
        non_system_idx = [i for i, m in enumerate(self._messages) if m["role"] != "system"]
        for i in sorted(non_system_idx[:n], reverse=True):
            self._messages.pop(i)
            self._token_counts.pop(i)

    @property
    def messages(self) -> list:
        return list(self._messages)


# Usage example
budget = TokenBudget(model="gpt-4", max_context=128_000, reserved_for_reply=2_048)
budget.add_message("system", "You are an agent that answers questions about code.")
budget.add_message("user", "What is BPE?")
budget.add_message("assistant", "BPE is a subword tokenisation algorithm...")
added = budget.add_message("user", "Show me an example.")
print(f"Message added: {added}")
print(f"Used: {budget.used_tokens} tokens, {budget.remaining_for_reply} remaining for reply")
